  ('medical-tech-moex-20814', 'medical-tech', 'medical-tech-moex-093-9168e375', 'sub-medical-tech-03', NULL, 'single_choice', '作血小板抗體檢驗，可測得抗體；若改用chloroquine處理後之血小板則反應消失；其可能的解釋為： 病人同時有HLA抗體與血小板特異抗體 病人可能有HLA抗體而無血小板特異抗體 病人可能有血小板特異抗體而無HLA抗體 病人的抗體反應是屬非特異干擾，與HLA或血小板特異抗體無涉', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:16+00:00", "source_pdf_sha1": "33d4b0cf0707", "answer_pdf_sha1": "2b394db97a23", "source_family": "moex-gov-tw", "moex": {"exam_code": "093020", "c": "105", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血液學與血庫學", "year": "093", "exam_name": "093年第一次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 71, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
